import asyncio
import websockets
from typing import Dict, List

class InventorySystem:
    def __init__(self):
        self.items = {}  # dictionary of items with their corresponding owners

    async def add_item(self, item_id: int, owner: str) -> None:
        """Add an item to the inventory."""
        if item_id not in self.items:
            self.items[item_id] = [owner]
        else:
            self.items[item_id].append(owner)

    async def remove_item(self, item_id: int, owner: str) -> None:
        """Remove an item from the inventory."""
        if item_id in self.items and owner in self.items[item_id]:
            self.items[item_id].remove(owner)

    async def transfer_item(self, item_id: int, from_player: str, to_player: str) -> None:
        """Transfer an item between players."""
        if item_id in self.items and from_player in self.items[item_id] and to_player not in self.items[item_id]:
            self.items[item_id].remove(from_player)
            self.items[item_id].append(to_player)

    async def update_ownership(self, item_id: int, new_owner: str) -> None:
        """Update the ownership of an item."""
        if item_id in self.items and new_owner not in self.items[item_id]:
            self.items[item_id].append(new_owner)

class GameServer:
    def __init__(self):
        self.inventory = InventorySystem()

    async def handle_client_request(self, client_id: int, request: Dict[str, str]) -> None:
        """Handle a client's request."""
        if "action" in request and "item_id" in request:
            action = request["action"]
            item_id = int(request["item_id"])
            if action == "add":
                await self.inventory.add_item(item_id, client_id)
            elif action == "remove":
                await self.inventory.remove_item(item_id, client_id)
            elif action == "transfer":
                to_player = request["to_player"]
                await self.inventory.transfer_item(item_id, client_id, to_player)
            elif action == "update_ownership":
                new_owner = request["new_owner"]
                await self.inventory.update_ownership(item_id, new_owner)
        else:
            raise ValueError("Invalid request")